#!/usr/bin/env python3
"""Real-time ad-creative tracker. Reads ClickUp on each request and renders the dashboard.
Env: CLICKUP_TOKEN. Run: gunicorn app:app"""
import os, json, base64, time, urllib.request, urllib.error
from datetime import datetime, timezone
try:
    from zoneinfo import ZoneInfo
    LONDON = ZoneInfo("Europe/London")
except Exception:
    LONDON = timezone.utc
from flask import Flask, Response

TEMPLATE = base64.b64decode("").decode()

LIST_TO_CLIENT = {
    "901213433755": "Mission Beard", "901212351334": "Brylamar",
    "901216572550": "Squeak n Snap", "901216938255": "Peela Nails",
    "901217825368": "Vita Sciences", "901219086285": "Boy Box",
    "901219393993": "Mowe Beauty",
}
CLIENT_ORDER = ["Vita Sciences", "Peela Nails", "Squeak n Snap", "Boy Box",
                "Brylamar", "Mission Beard", "Mowe Beauty"]
STAGE = {
    "idea stage": ("idea", "production"), "approved": ("approved", "production"),
    "sent to graphic designer": ("design", "production"),
    "sent to video editor": ("edit", "production"),
    "ready for review": ("review", "production"),
    "testing stage": ("testing", "live"), "testing": ("testing", "live"),
    "top performing": ("top", "live"), "top performer": ("top", "live"),
    "complete": ("complete", "done"), "rejected": ("rejected", "killed"),
}
BOARD_STAGES = {"approved", "design", "edit", "review"}

# statuses that count as "reached Testing"
TESTING_FAMILY = {"testing stage", "testing", "top performing", "top performer"}
# a status change only registers after standing for 15 minutes (accidental-flip guard)
BUFFER_MS = 15 * 60 * 1000

_CACHE = {"html": None, "ts": 0}
CACHE_TTL = 30  # seconds; keeps it real-time while respecting ClickUp rate limits


def api_get(url, token):
    req = urllib.request.Request(url, headers={"Authorization": token})
    with urllib.request.urlopen(req, timeout=30) as r:
        return json.loads(r.read().decode())


def fetch_list(list_id, token):
    out, page = [], 0
    while True:
        url = ("https://api.clickup.com/api/v2/list/%s/task"
               "?include_closed=true&subtasks=false&page=%d" % (list_id, page))
        data = api_get(url, token)
        tasks = data.get("tasks", [])
        out.extend(tasks)
        if data.get("last_page") is True or not tasks:
            break
        page += 1
        if page > 50:
            break
    return out


def fetch_time_in_status_bulk(task_ids, token):
    """Fetch status-change history for tasks via ClickUp's 'Total Time in Status'
    ClickApp. Returns {task_id: history} or None if the ClickApp is unavailable."""
    out = {}
    for i in range(0, len(task_ids), 40):
        chunk = task_ids[i:i + 40]
        qs = "&".join("task_ids=%s" % t for t in chunk)
        url = "https://api.clickup.com/api/v2/task/bulk_time_in_status/task_ids?" + qs
        try:
            data = api_get(url, token)
        except Exception:
            return None
        if not isinstance(data, dict):
            return None
        # raw API keys by task id; some variants wrap in {"tasks": {...}}
        inner = data.get("tasks") if ("tasks" in data and isinstance(data.get("tasks"), dict)) else data
        for tid, hist in (inner or {}).items():
            if isinstance(hist, dict):
                out[tid] = hist
    return out if out else None


def testing_entered_at(hist, now_ms):
    """When did this task last enter a Testing-family status?
    Applies the 15-minute buffer: a change too recent (or a blip shorter than
    15 minutes in the history) does not count. Returns epoch ms or None."""
    if not isinstance(hist, dict):
        return None
    best = None
    cur = hist.get("current_status") or {}
    if (cur.get("status") or "").strip().lower() in TESTING_FAMILY:
        since = (cur.get("total_time") or {}).get("since")
        if since:
            s = int(since)
            if now_ms - s >= BUFFER_MS:
                best = s
    for h in hist.get("status_history") or []:
        if (h.get("status") or "").strip().lower() in TESTING_FAMILY:
            tt = h.get("total_time") or {}
            since, mins = tt.get("since"), tt.get("by_minute") or 0
            if since and mins >= 15:
                s = int(since)
                if best is None or s > best:
                    best = s
    return best


def build_html():
    token = os.environ.get("CLICKUP_TOKEN", "").strip()
    if not token:
        return "<h1>CLICKUP_TOKEN not configured</h1>"
    raw = []
    for lid in LIST_TO_CLIENT:
        raw.extend(fetch_list(lid, token))
    now_ms = int(time.time() * 1000)
    all_ids = [t.get("id") for t in raw if t.get("id")]
    hist_map = fetch_time_in_status_bulk(all_ids, token)  # None => ClickApp disabled
    rows = []
    last_by_client = {c: None for c in CLIENT_ORDER}
    global_last = 0
    for t in raw:
        lid = str(t.get("list", {}).get("id", ""))
        client = LIST_TO_CLIENT.get(lid)
        if not client:
            continue
        status = (t.get("status") or {}).get("status", "")
        stage, cat = STAGE.get(status, ("other", "production"))
        closed = t.get("date_closed") is not None
        created = int(t["date_created"]) if t.get("date_created") else None
        assignees = [a.get("username") for a in t.get("assignees", []) if a.get("username")]
        rows.append({
            "id": t.get("id"), "name": t.get("name", ""), "url": t.get("url", ""),
            "client": client, "stage": stage, "cat": cat, "assignees": assignees,
            "closed": closed,
            "board": (stage in BOARD_STAGES) and (not closed),
            "extra": (stage in ("idea", "testing")) and (not closed),
        })
        # when did this creative last enter Testing?
        if hist_map is not None:
            # exact mode: real status-change time (15-min buffer applied inside)
            entered = testing_entered_at(hist_map.get(t.get("id")), now_ms)
        else:
            # fallback: ClickApp disabled — approximate with creation date
            entered = created if (cat == "live" and created) else None
        if entered:
            if last_by_client[client] is None or entered > last_by_client[client]:
                last_by_client[client] = entered
            if entered > global_last:
                global_last = entered
    gen_label = datetime.now(LONDON).strftime("%-d %b %Y, %H:%M:%S %Z")
    html = (TEMPLATE
            .replace("__DATA__", json.dumps(rows, ensure_ascii=False))
            .replace("__CLIENTS__", json.dumps(CLIENT_ORDER, ensure_ascii=False))
            .replace("__LASTTESTCLIENT__", json.dumps(last_by_client))
            .replace("__LASTTEST__", str(global_last))
            .replace("__GEN__", gen_label)
            .replace("Auto-updates every 15 min", "Live \u2014 updates on every load"))
    return html


app = Flask(__name__)


@app.route("/")
def index():
    now = time.time()
    if _CACHE["html"] and (now - _CACHE["ts"] < CACHE_TTL):
        html = _CACHE["html"]
    else:
        try:
            html = build_html()
            _CACHE["html"] = html
            _CACHE["ts"] = now
        except Exception as e:
            if _CACHE["html"]:
                html = _CACHE["html"]  # serve last good copy on transient error
            else:
                return Response("<h1>Temporary error reading ClickUp</h1><pre>%s</pre>" % str(e)[:300],
                                status=503, mimetype="text/html")
    return Response(html, mimetype="text/html",
                    headers={"Cache-Control": "no-store, max-age=0"})


@app.route("/healthz")
def healthz():
    return "ok"


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.environ.get("PORT", "10000")))
